import cron from 'node-cron';
import { TaskModel } from '../models/Task';
import { NotificationLogModel } from '../models/NotificationLog';
import { sendNotification } from '../services/notificationService';
import dayjs from 'dayjs';

/**
 * Initialize the scheduling engine which triggers daily reminders based on task schedules.
 */
export const initializeSchedulingEngine = () => {
  // Schedule a cron job to check tasks every minute
  cron.schedule('* * * * *', async () => {
    try {
      const now = dayjs().utcOffset(7);

      // Fetch all tasks that are active
      const tasks = await TaskModel.find({ status: 'active' });

      tasks.forEach(async (task) => {
        const taskTime = dayjs(`${now.format('YYYY-MM-DD')} ${task.recurrence.time}`).utcOffset(7);

        // Check if it's time to send a notification
        if (now.isSame(taskTime, 'minute')) {
          let assignees = task.assignees;

          // Check for unavailable members and rotate
          while (assignees.length > 0) {
            const currentAssigneeId = assignees[task.rotationIndex];
            if (!task.unavailableMembers?.includes(currentAssigneeId)) {
              // Send notification
              const success = await sendNotification(currentAssigneeId, task);
              if (success) {
                // Log notification success
                await NotificationLogModel.create({
                  taskId: task.id,
                  sentAt: new Date(),
                  status: 'success',
                  retryCount: 0
                });

                // Update rotation index to next member
                task.rotationIndex = (task.rotationIndex + 1) % assignees.length;
                await task.save();

                break;
              } else {
                await handleNotificationFailure(task);
              }
            } else {
              // Update rotation index if member is unavailable
              task.rotationIndex = (task.rotationIndex + 1) % assignees.length;
            }
          }
        }
      });
    } catch (error) {
      console.error('Error in Cron Scheduler:', error);
    }
  });
};

/**
 * Handle a failed notification attempt.
 * @param task The task object whose notification sending failed.
 */
const handleNotificationFailure = async (task) => {
  // Log the failure attempt
  await NotificationLogModel.create({
    taskId: task.id,
    sentAt: new Date(),
    status: 'failed',
    retryCount: 1
  });

  // Additional retry logic can be implemented here
};
